// This node plays the role of db.py + get_user_by_name() + get_user_matches()
// In a real app, these would be database queries.
// For the workshop, we hardcode the same data from db.py

const profiles = [
  { user_id: 'user-1', name: 'Alice', age: 28, gender: 'woman', looking_for: 'relationship', bio: 'I love hiking, cooking, and reading sci-fi.', latitude: 40.7128, longitude: -74.0060 },
  { user_id: 'user-2', name: 'Bob',   age: 30, gender: 'man',   looking_for: 'relationship', bio: 'Big fan of hiking, board games, and cooking new recipes.', latitude: 40.7580, longitude: -73.9855 },
  { user_id: 'user-3', name: 'Charlie', age: 26, gender: 'man', looking_for: 'casual', bio: 'Coffee addict. Let\'s find the best espresso in town.', latitude: 40.7306, longitude: -73.9866 },
  { user_id: 'user-4', name: 'Diana', age: 29, gender: 'woman', looking_for: 'relationship', bio: 'Movie buff, love exploring art galleries and trying street food.', latitude: 40.7282, longitude: -73.9943 },
  { user_id: 'user-5', name: 'Eve',   age: 24, gender: 'woman', looking_for: 'casual', bio: 'Looking for someone to go to live rock concerts with!', latitude: 40.7484, longitude: -73.9857 },
  { user_id: 'user-6', name: 'Frank', age: 32, gender: 'man',   looking_for: 'relationship', bio: 'Quiet nights in, cooking pasta, and watching documentaries.', latitude: 40.7112, longitude: -74.0055 }
];

const matches = [
  { match_id: 'match-1', user1_id: 'user-1', user2_id: 'user-2' },
  { match_id: 'match-2', user1_id: 'user-3', user2_id: 'user-5' }
];

// Get inputs from the webhook
const username  = $input.first().json.body.username;
const budget    = $input.first().json.body.budget;
const time      = $input.first().json.body.time;
const specification = $input.first().json.body.specification || 'None';

// Find the user by name (same as get_user_by_name)
const user = profiles.find(p => p.name.toLowerCase() === username.toLowerCase());
if (!user) {
  throw new Error(`User '${username}' not found`);
}

// Find their match (same as get_user_matches)
const matchRecord = matches.find(m => m.user1_id === user.user_id || m.user2_id === user.user_id);
if (!matchRecord) {
  throw new Error(`No match found for user '${username}'`);
}

const matchedUserId = matchRecord.user1_id === user.user_id ? matchRecord.user2_id : matchRecord.user1_id;
const matchedUser = profiles.find(p => p.user_id === matchedUserId);

return [{ json: { user, matchedUser, budget, time, specification } }];

// This node replicates calculate_distance() from utils.py
// It uses the Haversine formula — the correct way to measure
// distance between two GPS coordinates on a sphere.

const { user, matchedUser, budget, time, specification } = $input.first().json;

function haversineDistance(lat1, lon1, lat2, lon2) {
  const R = 6371.0; // Earth radius in km
  const toRad = deg => deg * Math.PI / 180;
  const dlat  = toRad(lat2 - lat1);
  const dlon  = toRad(lon2 - lon1);
  const a = Math.sin(dlat/2)**2 +
            Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dlon/2)**2;
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return Math.round(R * c * 100) / 100;
}

const distance = haversineDistance(
  user.latitude, user.longitude,
  matchedUser.latitude, matchedUser.longitude
);

return [{ json: { user, matchedUser, distance, budget, time, specification } }];

// This node builds the prompt — same as what main.py does
// when it assembles the `data` string before calling run()

const { user, matchedUser, distance, budget, time, specification } = $input.first().json;

const systemPrompt = `You are given the information about two people which includes the following:
Your job is to suggest a date idea based on the above information provided and you must return the response in the following json format. No markdown only simple json as follows:
Output JSON only with this shape:
{
  "suggestions": [
    {
      "title": "short title",
      "plan": "1-3 sentence plan",
      "why_it_fits": "1 sentence",
      "location_hint": "concise location guidance",
      "estimated_cost": "free | low | medium | high",
      "ideal_time": "morning | afternoon | evening"
    }
  ]
}
Rules:
- Output valid JSON only. No markdown.
- Use the provided distance/location context to keep travel reasonable.
- Avoid unsafe, illegal, or overly risky activities.
- Do not invent specific real-world venues or addresses.
- Respect preferences such as budget, time, outdoors, alcohol, accessibility, and dietary needs.
- Keep suggestions varied and realistic.
The information about the user, his/her match and the date requirements is provided below:`;

const userContext = `
The complete data about user1 is ${JSON.stringify(user)} and his/her match is ${JSON.stringify(matchedUser)} and the distance between them is ${distance} km and the budget for the date is ${budget} and the time is ${time} and some other specifications include ${specification}`;

const fullPrompt = systemPrompt + userContext;

return [{ json: { fullPrompt, user, matchedUser, distance, budget, time, specification } }];

// This node does the same cleanup as main.py:
// raw_content.strip().strip('`').removeprefix('json').strip()
// then JSON.parse() it

const rawText = $input.first().json.candidates[0].content.parts[0].text;

// Strip markdown code fences if the LLM added them
const cleaned = rawText.replace(/```json|```/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  throw new Error('Failed to parse LLM response as JSON. Raw response: ' + rawText);
}

return [{ json: parsed }];
